int ucr_03_bspd_pack(
    uint8_t *dst_p,
    const struct ucr_03_bspd_t *src_p,
    size_t size)
{
    uint32_t bspd_current;

    if (size < 8u) {
        return (-EINVAL);
    }

    memset(&dst_p[0], 0, 8);

    memcpy(&bspd_current, &src_p->bspd_current, sizeof(bspd_current));
    dst_p[0] |= pack_left_shift_u32(bspd_current, 0u, 0xffu);
    dst_p[1] |= pack_right_shift_u32(bspd_current, 8u, 0xffu);
    dst_p[2] |= pack_right_shift_u32(bspd_current, 16u, 0xffu);
    dst_p[3] |= pack_right_shift_u32(bspd_current, 24u, 0xffu);

    return (8);
}

int ucr_03_bspd_unpack(
    struct ucr_03_bspd_t *dst_p,
    const uint8_t *src_p,
    size_t size)
{
    uint32_t bspd_current;

    if (size < 8u) {
        return (-EINVAL);
    }

    bspd_current = unpack_right_shift_u32(src_p[0], 0u, 0xffu);
    bspd_current |= unpack_left_shift_u32(src_p[1], 8u, 0xffu);
    bspd_current |= unpack_left_shift_u32(src_p[2], 16u, 0xffu);
    bspd_current |= unpack_left_shift_u32(src_p[3], 24u, 0xffu);
    memcpy(&dst_p->bspd_current, &bspd_current, sizeof(dst_p->bspd_current));

    return (0);
}

